import t from"../docs/public/screenshots/translations-page.png";import a from"../docs/public/screenshots/translations-filters.png";import o from"../docs/public/screenshots/translation-editor-html.png";import{_ as n,o as i,c as r,ag as l}from"./chunks/framework.KHntoz-C.js";const k=JSON.parse('{"title":"Translation Management","description":"","frontmatter":{},"headers":[],"relativePath":"features/translations.md","filePath":"features/translations.md"}'),s={name:"features/translations.md"};function d(c,e,h,p,g,u){return i(),r("div",null,[...e[0]||(e[0]=[l('<h1 id="translation-management" tabindex="-1">Translation Management <a class="header-anchor" href="#translation-management" aria-label="Permalink to &quot;Translation Management&quot;">​</a></h1><p>The Translations page (<code>/lingua/translations/{locale?}</code>) lets you browse, filter, and edit every translation string.</p><figure style="margin:0 !important;max-width:100%;"><img src="'+t+'" alt="Lingua translations page"><figcaption>Translations page — with locale switcher, group filter, and inline editor.</figcaption></figure><h2 id="navigating-translations" tabindex="-1">Navigating translations <a class="header-anchor" href="#navigating-translations" aria-label="Permalink to &quot;Navigating translations&quot;">​</a></h2><h3 id="locale-switcher" tabindex="-1">Locale switcher <a class="header-anchor" href="#locale-switcher" aria-label="Permalink to &quot;Locale switcher&quot;">​</a></h3><p>The locale tabs at the top of the page let you switch between installed languages. The URL updates to <code>/lingua/translations/{locale}</code> so every view is bookmarkable and shareable.</p><p>The <strong>default locale</strong> column is always shown on the left as a reference — you edit the selected locale on the right.</p><h3 id="filtering" tabindex="-1">Filtering <a class="header-anchor" href="#filtering" aria-label="Permalink to &quot;Filtering&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Filter</th><th>Description</th></tr></thead><tbody><tr><td><strong>Search</strong></td><td>Searches across group name, key, and all locale values</td></tr><tr><td><strong>Group</strong></td><td>Filters to a specific group (e.g. <code>auth</code>, <code>validation</code>, <code>single</code>)</td></tr><tr><td><strong>Type</strong></td><td>Filters by <code>text</code>, <code>html</code>, or <code>markdown</code></td></tr><tr><td><strong>Show only missing</strong></td><td>Shows only strings with no value in the selected locale</td></tr></tbody></table><figure style="margin:0 !important;max-width:640px;"><img src="'+a+'" alt="Translation filters"><figcaption>Filtering to show only missing French translations in the validation group.</figcaption></figure><h3 id="pagination" tabindex="-1">Pagination <a class="header-anchor" href="#pagination" aria-label="Permalink to &quot;Pagination&quot;">​</a></h3><p>Results are paginated with a configurable per-page count (25 / 50 / 100). The current page and per-page setting are persisted in the URL query string.</p><h2 id="editing-translations" tabindex="-1">Editing translations <a class="header-anchor" href="#editing-translations" aria-label="Permalink to &quot;Editing translations&quot;">​</a></h2><h3 id="inline-editing" tabindex="-1">Inline editing <a class="header-anchor" href="#inline-editing" aria-label="Permalink to &quot;Inline editing&quot;">​</a></h3><p>Click directly into the translation cell to start editing. Changes are saved on blur (when you click away or press Tab).</p><ul><li><strong>Plain text</strong> translations use a simple <code>&lt;textarea&gt;</code></li><li><strong>HTML</strong> translations open the TipTap rich-text editor</li><li><strong>Markdown</strong> translations open the TipTap markdown editor</li></ul><figure style="margin:0 !important;max-width:640px;"><img src="'+o+`" alt="HTML translation editor"><figcaption>The TipTap HTML editor for rich-text translations.</figcaption></figure><h3 id="sync-from-default" tabindex="-1">Sync from default <a class="header-anchor" href="#sync-from-default" aria-label="Permalink to &quot;Sync from default&quot;">​</a></h3><p>Each translation row has a <strong>Sync from default</strong> button (↺). Clicking it copies the default locale&#39;s value to the current locale — useful as a starting point when you only need minor wording changes.</p><h3 id="edit-modal" tabindex="-1">Edit modal <a class="header-anchor" href="#edit-modal" aria-label="Permalink to &quot;Edit modal&quot;">​</a></h3><p>For the default locale, click the pencil icon to open the Edit modal, where you can change the translation type (text / html / markdown) as well as the value.</p><div class="tip custom-block"><p class="custom-block-title">Changing translation types</p><p>If you change a translation from <code>text</code> to <code>html</code>, the inline editor on the row will immediately switch to TipTap. The stored value is unchanged — only the editor changes.</p></div><h2 id="creating-translations" tabindex="-1">Creating translations <a class="header-anchor" href="#creating-translations" aria-label="Permalink to &quot;Creating translations&quot;">​</a></h2><p>Click <strong>New Translation</strong> to create a custom entry. Fill in:</p><ul><li><strong>Group</strong> — the file name equivalent (e.g. <code>marketing</code>, <code>emails</code>)</li><li><strong>Key</strong> — the key within the group (e.g. <code>hero_title</code>)</li><li><strong>Type</strong> — <code>text</code>, <code>html</code>, or <code>markdown</code></li><li><strong>Value</strong> — the translation for the default locale</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>group: marketing</span></span>
<span class="line"><span>key:   hero_title</span></span>
<span class="line"><span>type:  text</span></span>
<span class="line"><span>value: Build faster, together.</span></span></code></pre></div><p>The new key is immediately available via <code>__(&#39;marketing.hero_title&#39;)</code>.</p><div class="warning custom-block"><p class="custom-block-title">Vendor translations</p><p>You cannot create translations directly in a vendor group (e.g. <code>validation</code>, <code>auth</code>). Those groups are owned by Laravel or other packages and are synced automatically. If you want to override a vendor string, edit it directly on the translations page.</p></div><h2 id="deleting-translations" tabindex="-1">Deleting translations <a class="header-anchor" href="#deleting-translations" aria-label="Permalink to &quot;Deleting translations&quot;">​</a></h2><h3 id="delete-for-a-specific-locale" tabindex="-1">Delete for a specific locale <a class="header-anchor" href="#delete-for-a-specific-locale" aria-label="Permalink to &quot;Delete for a specific locale&quot;">​</a></h3><p>On any non-default locale, the delete button removes only that locale&#39;s value from the JSON column. The translation key continues to exist; it just falls back to the default locale.</p><h3 id="delete-entirely" tabindex="-1">Delete entirely <a class="header-anchor" href="#delete-entirely" aria-label="Permalink to &quot;Delete entirely&quot;">​</a></h3><p>On the default locale view, the delete button removes the entire row from <code>language_lines</code>. Use this to clean up keys that are no longer used in your codebase.</p><div class="danger custom-block"><p class="custom-block-title">Vendor translation protection</p><p>Vendor translations cannot be deleted. Attempting to do so shows a warning and dispatches a <code>vendor_translation_protected</code> event. You can only <strong>edit</strong> vendor translation values.</p></div><h2 id="copy-key-to-clipboard" tabindex="-1">Copy key to clipboard <a class="header-anchor" href="#copy-key-to-clipboard" aria-label="Permalink to &quot;Copy key to clipboard&quot;">​</a></h2><p>Every row has a clipboard icon that copies the full <code>group.key</code> reference (e.g. <code>auth.failed</code>) to your clipboard — handy when referencing keys in Blade or PHP.</p><h2 id="keyboard-shortcuts" tabindex="-1">Keyboard shortcuts <a class="header-anchor" href="#keyboard-shortcuts" aria-label="Permalink to &quot;Keyboard shortcuts&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Key</th><th>Action</th></tr></thead><tbody><tr><td><code>Tab</code></td><td>Save current field and move to next</td></tr><tr><td><code>Shift + Tab</code></td><td>Save current field and move to previous</td></tr><tr><td><code>Escape</code></td><td>Discard changes and close editor</td></tr></tbody></table>`,38)])])}const v=n(s,[["render",d]]);export{k as __pageData,v as default};
